import React, { useState } from 'react';
import {
    TextField,
    Button,
    Select,
    MenuItem,
    FormControl,
    InputLabel,
    Box,
    Typography,
} from '@mui/material';
import { activitiesAPI } from '../services/api';

const ActivityForm = ({ onActivityLogged }) => {
    const [formData, setFormData] = useState({
        activity_type: 'Running',
        duration: '',
        distance: '',
        calories_burned: '',
        notes: '',
        date: new Date().toISOString().split('T')[0],
    });

    const handleSubmit = async (e) => {
        e.preventDefault();
        try {
            // Validate required fields
            if (!formData.duration || formData.duration === '') {
                alert('Duration is required');
                return;
            }

            // Convert string values to numbers, only include if provided
            const activityData = {
                activity_type: formData.activity_type,
                duration: parseInt(formData.duration) || 0,
                date: formData.date,
            };

            // Only include optional fields if they have values
            if (formData.distance && formData.distance !== '') {
                activityData.distance = parseFloat(formData.distance);
            }
            if (formData.calories_burned && formData.calories_burned !== '') {
                activityData.calories_burned = parseFloat(formData.calories_burned);
            }
            if (formData.notes && formData.notes !== '') {
                activityData.notes = formData.notes;
            }

            console.log('Sending activity data:', activityData);
            await activitiesAPI.logActivity(activityData);
            setFormData({
                activity_type: 'Running',
                duration: '',
                distance: '',
                calories_burned: '',
                notes: '',
                date: new Date().toISOString().split('T')[0],
            });
            onActivityLogged && onActivityLogged();
        } catch (error) {
            console.error('Error logging activity:', error);
            alert('Failed to log activity: ' + (error.response?.data?.error || error.message));
        }
    };

    return (
        <Box component="form" onSubmit={handleSubmit} sx={{ mt: 3 }}>
            <Typography variant="h6" gutterBottom>
                Log New Activity
            </Typography>

            <FormControl fullWidth margin="normal">
                <InputLabel>Activity Type</InputLabel>
                <Select
                    value={formData.activity_type}
                    onChange={(e) => setFormData({...formData, activity_type: e.target.value})}
                    label="Activity Type"
                >
                    <MenuItem value="Running">Running</MenuItem>
                    <MenuItem value="Cycling">Cycling</MenuItem>
                    <MenuItem value="Weightlifting">Weightlifting</MenuItem>
                    <MenuItem value="Yoga">Yoga</MenuItem>
                    <MenuItem value="Swimming">Swimming</MenuItem>
                    <MenuItem value="Walking">Walking</MenuItem>
                </Select>
            </FormControl>

            <TextField
                fullWidth
                margin="normal"
                label="Duration (minutes)"
                type="number"
                value={formData.duration}
                onChange={(e) => setFormData({...formData, duration: e.target.value})}
                required
            />

            <TextField
                fullWidth
                margin="normal"
                label="Distance (km)"
                type="number"
                value={formData.distance}
                onChange={(e) => setFormData({...formData, distance: e.target.value})}
            />

            <TextField
                fullWidth
                margin="normal"
                label="Calories Burned"
                type="number"
                value={formData.calories_burned}
                onChange={(e) => setFormData({...formData, calories_burned: e.target.value})}
            />

            <TextField
                fullWidth
                margin="normal"
                label="Date"
                type="date"
                value={formData.date}
                onChange={(e) => setFormData({...formData, date: e.target.value})}
                InputLabelProps={{ shrink: true }}
            />

            <TextField
                fullWidth
                margin="normal"
                label="Notes"
                multiline
                rows={3}
                value={formData.notes}
                onChange={(e) => setFormData({...formData, notes: e.target.value})}
            />

            <Button type="submit" variant="contained" color="primary" sx={{ mt: 2 }}>
                Log Activity
            </Button>
        </Box>
    );
};

export default ActivityForm;
